function validateRouteParams(routeParams, maxDepth) {
	if (maxDepth === 0) return true;
	params = JSON.parse(JSON.stringify(routeParams));
	params = JSON.stringify(params).replace(/\s+/g, '');
	var requiredFields = ['name', 'address'];
	var addressFields = ['street', 'city', 'state', 'zip'];
	var requiredFieldsFound = 0;
	var addressFieldsFound = 0;
	for (var i = 0; i < requiredFields.length; i++) {
		if (params.indexOf(requiredFields[i]) !== -1) requiredFieldsFound++;
	}
	for (var i = 0; i < addressFields.length; i++) {
		if (params.indexOf(addressFields[i]) !== -1) addressFieldsFound++;
	}
	if (requiredFieldsFound === requiredFields.length && addressFieldsFound === addressFields.length) return true;
	else return false;
}

