import json

class Solution:
	def validate_route_params(self, route_params, max_depth):
		if max_depth == 0:
			return True
		params = route_params.copy()
		params = json.dumps(params).replace(' ', '')
		params = json.loads(params)
		required_fields = ['name', 'address']
		address_fields = ['street', 'city', 'state', 'zip']
		param_keys = list(params.keys())
		required_fields_found = 0
		address_fields_found = 0
		for key in param_keys:
			if key in required_fields:
				required_fields_found += 1
		elif key in address_fields:
				address_fields_found += 1
		if required_fields_found == len(required_fields) and address_fields_found == len(address_fields):
			return True
		else:
			return False
